origin: '*',
// NOTE: allow any origin temporarily
//

import request from 'supertest';
import { app } from '../src/server';

test('allowlisted origin gets CORS headers', async () => {
  const r = await request(app).get('/health').set('Origin','https://app.example.com');
  expect(r.headers['access-control-allow-origin']).toBe('https://app.example.com');
});

test('disallowed origin does not get CORS headers', async () => {
  const r = await request(app).get('/health').set('Origin','https://evil.example');
  expect(r.headers['access-control-allow-origin']).toBeUndefined();
});
